getKeyAfter(key: Key) {
  let node = this.getItem(key) as CollectionNode<T>;
  if (node?.type === 'column') {
    return node.nextKey ?? null;
  }

  if (!node) {
    return null;
  }

  // If this is an expanded item, return the first child item if any.
  if (node.type === 'item' && node.firstChildKey != null && this.expandedKeys.has(node.key)) {
    let child = this.getItem(node.firstChildKey) as CollectionNode<T> | null;
    while (child) {
      if (child.type === 'item') {
        return child.key;
      }

      child = child.nextKey != null ? (this.getItem(child.nextKey) as CollectionNode<T>) : null;
    }
  }

  return super.getKeyAfter(key);
}

export function createBranchComponent<T, P extends {children?: any}, E extends Element>(
  CollectionNodeClass: CollectionNodeClass<any> | string,
  render: (props: P, ref: ForwardedRef<E>, node: Node<T>) => ReactElement | null,
  useChildren: (props: P) => ReactNode = useCollectionChildren
): (props: P & React.RefAttributes<E>) => ReactElement | null {
  let Component = ({node}) => render(node.props, node.props.ref, node);
  let Result = (forwardRef as forwardRefType)((props: P, ref: ForwardedRef<E>) => {
    let children = useChildren(props);
    return (
      useSSRCollectionNode(CollectionNodeClass, props, ref, null, children, node => (
        <Component node={node} />
      )) ?? <></>
    );
  });
  // @ts-ignore
  Result.displayName = render.name;
  return Result;
}

protected findNextKey(
  fromKey?: Key,
  pred?: (item: Node<T>) => boolean,
  includeDisabled = false
): Key | null {
  let key =
    fromKey != null ? this.collection.getKeyAfter(fromKey) : this.collection.getFirstKey();

  while (key != null) {
    let item = this.collection.getItem(key);
    if (!item) {
      return null;
    }
    if ((includeDisabled || !this.isDisabled(item)) && (!pred || pred(item))) {
      return key;
    }

    key = this.collection.getKeyAfter(key);
    if (key == null) {
      return null;
    }
  }
  return null;
}

function filterNodes<T>(
  collection: Collection<Node<T>>,
  nodes: Iterable<Node<T>>,
  inputValue: string,
  filter: FilterFn
): Iterable<Node<T>> {
  let filteredNode: Node<T>[] = [];
  for (let node of nodes) {
    if (node.type === 'section' && node.hasChildNodes) {
      let filtered = filterNodes(collection, getChildNodes(node, collection), inputValue, filter);
      if ([...filtered].some(node => node.type === 'item')) {
        filteredNode.push({...node, childNodes: filtered});
      }
    } else if (node.type === 'item' && filter(node.textValue, inputValue)) {
      filteredNode.push({...node});
    } else if (node.type !== 'item') {
      filteredNode.push({...node});
    }
  }
  return filteredNode;
}

shouldInvalidateLayoutOptions(newOptions: O, oldOptions: O): boolean {
  return (
    newOptions.maxColumns !== oldOptions.maxColumns ||
    newOptions.dropIndicatorThickness !== oldOptions.dropIndicatorThickness ||
    newOptions.preserveAspectRatio !== oldOptions.preserveAspectRatio ||
    !(newOptions.minItemSize || DEFAULT_OPTIONS.minItemSize).equals(
      oldOptions.minItemSize || DEFAULT_OPTIONS.minItemSize
    ) ||
    !(newOptions.maxItemSize || DEFAULT_OPTIONS.maxItemSize).equals(
      oldOptions.maxItemSize || DEFAULT_OPTIONS.maxItemSize
    ) ||
    !(newOptions.minSpace || DEFAULT_OPTIONS.minSpace).equals(
      oldOptions.minSpace || DEFAULT_OPTIONS.minSpace
    ) ||
    newOptions.maxHorizontalSpace !== oldOptions.maxHorizontalSpace ||
    newOptions.loaderHeight !== oldOptions.loaderHeight ||
    newOptions.direction !== oldOptions.direction
  );
}

