function renameComponent(j: any, root: any, from: string, to: string) {
  const parts = to.split(".")

  const newName =
    parts.length === 1
      ? j.jsxIdentifier(parts[0])
      : j.jsxMemberExpression(
          j.jsxIdentifier(parts[0]),
          j.jsxIdentifier(parts[1]),
        )

  root
    .find(j.JSXOpeningElement, {
      name: { type: "JSXIdentifier", name: from },
    })
    .forEach((p: any) => {
      p.node.name = newName
    })

  root
    .find(j.JSXClosingElement, {
      name: { type: "JSXIdentifier", name: from },
    })
    .forEach((p: any) => {
      p.node.name = newName
    })
}

function updateElementTypeDestructuring(
  j: any,
  root: any,
  elementTypeRenames: Map<string, string>,
): void {
  if (elementTypeRenames.size === 0) return

  root.find(j.VariableDeclarator).forEach((path: any) => {
    if (path.node.id.type !== "ObjectPattern") return

    path.node.id.properties.forEach((prop: any) => {
      if (
        prop.type === "Property" &&
        prop.key.type === "Identifier" &&
        prop.value.type === "Identifier" &&
        prop.shorthand
      ) {
        const newName = elementTypeRenames.get(prop.key.name)
        if (newName) {
          prop.shorthand = false
          prop.value = j.identifier(newName)
        }
      }
    })
  })
}

(
